/* Handle Refresh Button */
window.handleRefresh = async function() {
  const refreshBtn = document.getElementById("refreshBtn");
  if (!refreshBtn) return;
  
  // Disable button and add loading state
  refreshBtn.classList.add("btn-refresh-loading");
  refreshBtn.disabled = true;
  
  const refreshText = document.getElementById("refreshText");
  if (refreshText) {
    refreshText.textContent = "กำลังโหลด...";
  }
  
  try {
    // Call fetch data with force update
    await fetchData(true);
  } catch (error) {
    console.error("Refresh error:", error);
    showToast("เกิดข้อผิดพลาดในการรีเฟรช", true);
  } finally {
    // Re-enable button and remove loading state
    refreshBtn.classList.remove("btn-refresh-loading");
    refreshBtn.disabled = false;
    
    if (refreshText) {
      refreshText.textContent = "รีเฟรช";
    }
  }
};